state n = 0;
label n;
button "+" { n = n + 1; }

state n = 10;
label n;
button "-" { n = n - 1; }

state n = 0;
label n;
button "+5" { n = n + 5; }

state n = 3;
label n;
row {
  button "up" { n = n + 1; }
  button "down" { n = n - 1; }
}

state n = 0;
label n;
button "+" { n = n + 1; }
button "reset" { n = 0; }

state n = 1;
label n;
button "double" { n = n * 2; }

state on = false;
button "toggle" { if on { on = false; } else { on = true; } }
if on { label "hello"; }

state shown = false;
button "reveal" { shown = true; }
if shown { label "secret"; }

state name = "";
input name;
label "Hello, " + name + "!";

state s = "";
input s;
label s;

state s = "";
input s;
label "You said: " + s;

state t = 0;
label t;
button "add 2" { t = t + 2; }
button "add 3" { t = t + 3; }

state t = 0;
label "Total: $" + t;
button "+10" { t = t + 10; }

state n = 0;
label n;
button "+1" { n = n + 1; }
if n % 2 == 0 { label "even"; } else { label "odd"; }

state n = 0;
label n;
button "+" { if n < 3 { n = n + 1; } }

state n = 1;
label n;
button "-" { if n > 0 { n = n - 1; } }

state a = 0;
state b = 0;
label a;
label b;
button "a+" { a = a + 1; }
button "b+" { b = b + 1; }

state m = 0;
button "mode" { m = m + 1; if m > 2 { m = 0; } }
if m == 0 { label "red"; } else if m == 1 { label "green"; } else { label "blue"; }

state s = 0;
label "Score: " + s;
button "goal" { s = s + 1; }

state n = 5;
label n;
button "tick" { if n > 0 { n = n - 1; } }
if n == 0 { label "done"; }

state lit = false;
row {
  button "on" { lit = true; }
  button "off" { lit = false; }
}
if lit { label "LIGHT ON"; }

state n = 50;
label n;
row {
  button "+10" { n = n + 10; }
  button "-10" { n = n - 10; }
}

state n = 2;
label n;
button "triple" { n = n * 3; }

state a = 0;
state b = 0;
row {
  button "left+" { a = a + 1; }
  button "right+" { b = b + 1; }
}
label a + b;

state name = "";
input name;
if name == "" { label "Hello, stranger"; } else { label "Hello, " + name; }

state n = 0;
label n;
button "+3" { n = n + 3; }
if n >= 10 { label "big"; }

state y = 0;
state n = 0;
row {
  button "yes" { y = y + 1; }
  button "no" { n = n + 1; }
}
label "Yes: " + y;
label "No: " + n;

state n = 0;
label n;
button "+" { n = n + 1; }
if n >= 5 { label "limit reached"; }

state n = 0;
label n;
button "next even" { n = n + 2; }

state s = "";
input s;
if s == "" { label "empty"; }

state n = 1;
state vis = true;
button "toggle" { if vis { vis = false; } else { vis = true; } }
if vis { label n; }

state n = 1;
label n;
button "double" { n = n * 2; }
if n > 8 { label "too big"; }

state n = 100;
label n;
button "spend 25" { n = n - 25; }

state n = 0;
button "+1" { n = n + 1; }
label n % 3;

state started = false;
if started { label "Let's go"; } else { label "Welcome"; }
button "start" { started = true; }

state s = 0;
label s;
row {
  button "correct" { s = s + 1; }
  button "wrong" { if s > 0 { s = s - 1; } }
}

state t = 0;
label t + "s";
button "tick" { t = t + 1; }

state t = 0;
label t;
button "small +1" { t = t + 1; }
button "large +100" { t = t + 100; }

state f = "";
state l = "";
input f;
input l;
label f + " " + l;

state n = 3;
if n > 0 { label n; } else { label "none left"; }
button "-" { if n > 0 { n = n - 1; } }
